const BACKUP_KEY = 'st_stream_guard';
const POLL_INTERVAL = 2000;
const DEBOUNCE_DELAY = 1500;
const MAX_BACKUP_AGE_MS = 30 * 60 * 1000;
const PLUGIN_API = '/api/plugins/stream-guard';

let isGenerating = false;
let pollTimer = null;
let debounceTimer = null;
let lastSavedContent = '';
let serverPluginAvailable = false;
let currentGenerationChatId = '';
let recoveryToast = null;
let discardToast = null;

function getHeaders() {
    try {
        const h = SillyTavern.getRequestHeaders();
        if (h && h['X-CSRF-TOKEN']) return h;
    } catch {}
    return { 'Content-Type': 'application/json' };
}

async function pluginGet(path) {
    try {
        return await fetch(`${PLUGIN_API}${path}`, {
            method: 'GET',
            headers: getHeaders(),
            credentials: 'include',
        });
    } catch {
        return null;
    }
}

async function checkServerPlugin() {
    for (let i = 0; i < 3; i++) {
        try {
            const resp = await pluginGet('/backup');
            if (resp && resp.ok) {
                serverPluginAvailable = true;
                return;
            }
            if (resp && resp.status === 404) {
                serverPluginAvailable = false;
                return;
            }
        } catch {}
        if (i < 2) await new Promise(r => setTimeout(r, 2000));
    }
    serverPluginAvailable = false;
}

(async () => {
    await new Promise(r => setTimeout(r, 3000));
    await checkServerPlugin();
    eventOn(tavern_events.GENERATION_STARTED, onGenerationStarted);
    eventOn(tavern_events.STREAM_TOKEN_RECEIVED, onStreamToken);
    eventOn(tavern_events.GENERATION_ENDED, onGenerationFinished);
    eventOn(tavern_events.GENERATION_STOPPED, onGenerationFinished);
    await checkAndRecover();
})();

function onGenerationStarted(type, option, dry_run) {
    if (dry_run) return;
    isGenerating = true;
    lastSavedContent = '';
    currentGenerationChatId = SillyTavern.getCurrentChatId() || '';
    stopPollBackup();
    pollTimer = setInterval(performBackup, POLL_INTERVAL);
    setTimeout(performBackup, 800);
}

function onStreamToken() {
    if (!isGenerating) return;
    if (debounceTimer) clearTimeout(debounceTimer);
    debounceTimer = setTimeout(performBackup, DEBOUNCE_DELAY);
}

function onGenerationFinished() {
    if (!isGenerating) return;
    isGenerating = false;
    stopPollBackup();
    if (debounceTimer) {
        clearTimeout(debounceTimer);
        debounceTimer = null;
    }
    clearAllBackups();
    lastSavedContent = '';
}

function stopPollBackup() {
    if (pollTimer) {
        clearInterval(pollTimer);
        pollTimer = null;
    }
}

function performBackup() {
    if (!isGenerating) return;
    try {
        const messages = getChatMessages(-1);
        if (!messages || messages.length === 0) return;
        const lastMsg = messages[0];
        const content = lastMsg.message || '';
        if (!content.trim() || content === lastSavedContent) return;
        lastSavedContent = content;
        localStorage.setItem(BACKUP_KEY, JSON.stringify({
            chatId: currentGenerationChatId || SillyTavern.getCurrentChatId() || '',
            charName: SillyTavern.name2 || '',
            messageId: lastMsg.message_id,
            name: lastMsg.name || '',
            role: lastMsg.role || 'assistant',
            content: content,
            contentLength: content.length,
            timestamp: Date.now(),
            source: 'client',
        }));
    } catch (e) {
        console.error('[StreamGuard] 备份出错:', e);
    }
}

async function checkAndRecover() {
    await new Promise(r => setTimeout(r, 1500));

    let clientBackup = null;
    try {
        const raw = localStorage.getItem(BACKUP_KEY);
        if (raw) {
            clientBackup = JSON.parse(raw);
        }
    } catch {}

    let serverBackup = null;
    if (serverPluginAvailable) {
        try {
            const resp = await pluginGet('/backup');
            if (resp && resp.ok) {
                const data = await resp.json();
                if (!data.empty && data.text) {
                    serverBackup = data;
                }
            }
        } catch {}
    }

    let backup = null;
    let backupSource = '';

    if (clientBackup && serverBackup) {
        if (serverBackup.textLength >= clientBackup.contentLength) {
            backup = {
                chatId: clientBackup.chatId || '',
                charName: clientBackup.charName || '',
                name: clientBackup.name || '',
                role: clientBackup.role || 'assistant',
                content: serverBackup.text,
                contentLength: serverBackup.textLength,
                timestamp: Math.max(clientBackup.timestamp || 0, serverBackup.timestamp || 0),
                source: 'server',
            };
            backupSource = `服务器端(${serverBackup.textLength}字)`;
        } else {
            backup = clientBackup;
            backupSource = `客户端(${clientBackup.contentLength}字)`;
        }
    } else if (serverBackup) {
        backup = {
            chatId: '', charName: '', name: '', role: 'assistant',
            content: serverBackup.text,
            contentLength: serverBackup.textLength,
            timestamp: serverBackup.timestamp,
            source: 'server',
        };
        backupSource = `服务器端(${serverBackup.textLength}字)`;
    } else if (clientBackup) {
        backup = clientBackup;
        backupSource = serverPluginAvailable
            ? `客户端(${clientBackup.contentLength}字) - 服务器端未捕获到流数据`
            : `客户端(${clientBackup.contentLength}字) - 服务器插件未安装`;
    }

    if (!backup) {
        return;
    }

    if (Date.now() - (backup.timestamp || 0) > MAX_BACKUP_AGE_MS) {
        clearAllBackups();
        return;
    }

    if (!backup.content || !backup.content.trim()) {
        clearAllBackups();
        return;
    }

    if (isContentInChat(backup.content)) {
        clearAllBackups();
        return;
    }

    showRecoveryUI(backup, backupSource);
}

function isContentInChat(content) {
    try {
        const lastId = getLastMessageId();
        if (lastId < 0) return false;
        const start = Math.max(0, lastId - 3);
        const msgs = getChatMessages(`${start}-${lastId}`);
        if (!msgs || msgs.length === 0) return false;
        const snippet = content.trim().substring(0, 100);
        if (!snippet) return false;
        for (const msg of msgs) {
            if (msg.message && msg.message.includes(snippet)) return true;
        }
    } catch {}
    return false;
}

function dismissAllToasts() {
    if (recoveryToast) {
        toastr.clear(recoveryToast);
        recoveryToast = null;
    }
    if (discardToast) {
        toastr.clear(discardToast);
        discardToast = null;
    }
}

function showRecoveryUI(backup, backupSource) {
    const minutesAgo = Math.max(1, Math.ceil((Date.now() - backup.timestamp) / 60000));
    const preview = backup.content.length > 150
        ? backup.content.substring(0, 150) + '...'
        : backup.content;

    const recoveryMsg =
        `${minutesAgo}分钟前的回复 | ${backup.name || '未知'} | ${backup.contentLength}字\n` +
        `来源: ${backupSource}\n` +
        `${preview}\n\n` +
        `<i class="fa-solid fa-arrow-pointer"></i> 点击恢复到聊天`;

    recoveryToast = toastr.warning(
        recoveryMsg,
        '<i class="fa-solid fa-shield-halved"></i> StreamGuard 发现未保存回复',
        {
            timeOut: 0,
            extendedTimeOut: 0,
            closeButton: true,
            escapeHtml: false,
            onclick: async () => {
                dismissAllToasts();
                await doRecover(backup, backupSource);
            },
        },
    );

    discardToast = toastr.info(
        '<i class="fa-solid fa-arrow-pointer"></i> 点击丢弃备份',
        '<i class="fa-solid fa-trash-can"></i> 不需要恢复？',
        {
            timeOut: 0,
            extendedTimeOut: 0,
            closeButton: true,
            escapeHtml: false,
            onclick: () => {
                dismissAllToasts();
                clearAllBackups();
                toastr.success(
                    '备份已丢弃',
                    '<i class="fa-solid fa-check"></i> 完成',
                    { escapeHtml: false },
                );
            },
        },
    );
}

async function doRecover(backup, backupSource) {
    try {
        await createChatMessages([{
            role: backup.role || 'assistant',
            name: backup.name || backup.charName || SillyTavern.name2 || 'Assistant',
            message: backup.content,
        }]);
        clearAllBackups();
        toastr.success(
            `恢复成功 (${backup.contentLength}字, ${backupSource})`,
            '<i class="fa-solid fa-check"></i> StreamGuard',
            { escapeHtml: false },
        );
    } catch (e) {
        console.error('[StreamGuard] 恢复出错:', e);
        try {
            builtin.copyText(backup.content);
            toastr.warning(
                '已复制到剪贴板，请手动粘贴',
                '<i class="fa-solid fa-clipboard"></i> 恢复失败',
                { escapeHtml: false },
            );
        } catch {
            toastr.error(
                'F12控制台查看内容',
                '<i class="fa-solid fa-triangle-exclamation"></i> 恢复失败',
                { escapeHtml: false },
            );
        }
    }
}

function clearAllBackups() {
    localStorage.removeItem(BACKUP_KEY);
    if (serverPluginAvailable) {
        pluginGet('/clear').catch(() => {});
    }
}
